const e={name:"heightForHeroes",msgBarSelector:document.querySelector("#msg-covid"),navBarSelector:document.querySelector("section.navigation"),init:function(){this.msgBarObserver(),this.navBarObserver()},msgBarObserver:function(){new ResizeObserver(t=>{t.forEach(s=>{e.msgBarHeight=s.target.clientHeight,e.setCSSProp()})}).observe(this.msgBarSelector)},navBarObserver:function(){new ResizeObserver(t=>{t.forEach(s=>{e.navBarHeight=s.target.clientHeight,e.setCSSProp()})}).observe(this.navBarSelector)},setCSSProp:function(){let r=this.msgBarHeight+this.navBarHeight;document.documentElement.style.setProperty("--size-height-for-hero",r+"px")}};e.init();
